export const INSTANCE_STRIDE_BYTES = 16
export const INSTANCE_STRIDE_F32 = 4

export const FIELD_OFFSET_BYTES = {
  position: 0,
  yOffset: 4,
  segHeight: 8,
  packedColor: 12,
} as const

export const FIELD_OFFSET_F32 = {
  position: 0,
  yOffset: 1,
  segHeight: 2,
  packedColor: 3,
} as const

export const GL_ATTRIBUTES: readonly GlAttributeLayout[] = [
  { name: 'a_position', components: 1, type: 'float', offsetBytes: 0, integer: false },
  { name: 'a_yOffset', components: 1, type: 'float', offsetBytes: 4, integer: false },
  { name: 'a_segHeight', components: 1, type: 'float', offsetBytes: 8, integer: false },
  { name: 'a_packedColor', components: 1, type: 'uint', offsetBytes: 12, integer: true },
]

export interface Instance {
  position: number
  yOffset: number
  segHeight: number
  packedColor: number
}

export function writeInstance(buf: ArrayBuffer, instanceIndex: number, inst: Instance) {
  const base = instanceIndex * 16
  const dv = new DataView(buf)
  dv.setFloat32(base + 0, inst.position, true)
  dv.setFloat32(base + 4, inst.yOffset, true)
  dv.setFloat32(base + 8, inst.segHeight, true)
  dv.setUint32(base + 12, inst.packedColor, true)
}
